@startuml

title "US027 – As Director, I want to define the Product Owner of a project."

class AssignProductOwnerUI <<boundary>> {
}

class AssignProductOwnerController {
  +AssignProductOwnerController
  +getProject(code)
  +getResource(name)
  +assignRole(resourceName, roleName)
}

class ProjectsMapper {
  +toDTO(project)
}

class ProjectTeamMapper {
  +toDto(resource)
}

class ProjectDTO {
  +ProjectDTO(code, projectName, startDate, endDate)
}

class ResourceDTO {
  +ResourceDTO(name, role, startDate, endDate, costPerHour, percentageOfAllocation)
}

class Company {
  +Company()
  +getProjectStore()
  +getProjectRoleStore()
}

class ProjectStore {
  +ProjectStore()
  +getProjectByCode()
}

class ProjectRoleStore {
  +ProjectRoleStore()
  +getProjectRole(roleName)
}

class Project {
  +Project()
  +getProjectTeam()
  +getSprintDuration()
  +getSprints()
  +hasCode()
}

class ProjectTeam {
  +ProjectTeam()
  +getResourceByName()
  +assignProjectRole(resource, startDate, sprintDuration, role)
  +saveResource(newResource)
  +checkIfRoleCurrentExistInTheProjectTeam(role, startDate)
}

class SprintList {
  +SprintList()
  +getCurrentSprint()
}

class Resource {
  +Resource()
  +Resource(originalResource)
  +isYourName(name)
  +isCurrent()
  +setRole(role)
  +setStartDate(startDate)
  +setEndDate(startDate)
  +isAvailableToSprint(startDate, sprintDuration)
  +copyUpdateProjectRoleOfAResource(originalResource, startDateNewRole, role)
}

class Sprint {
  +Sprint()
  +isCurrentSprint()
  +getEndDate()
}

AssignProductOwnerUI ..> AssignProductOwnerController : uses

AssignProductOwnerController ..> ProjectsMapper : uses
AssignProductOwnerController ..> ProjectTeamMapper : uses
AssignProductOwnerController ..> Company : uses
AssignProductOwnerController ..> ProjectTeam : uses
AssignProductOwnerController ..> Resource : uses

ProjectsMapper ..> ProjectDTO : creates
ProjectTeamMapper ..> ResourceDTO : creates

Company "1" --> "1" ProjectStore : has
Company "1" --> "1" ProjectRoleStore : has

ProjectStore "1" --> "*" Project : contains

Project "1" o-- "1" ProjectTeam : has
Project "1" --> "1" SprintList : has

ProjectTeam "1" --> "*" Resource : contains

SprintList "1" --> "*" Sprint : contains

@enduml
